cypher:
MATCH (p:Patent)-[:PUBLISHED_IN]->(:Country {code:'CN'})
WHERE NOT EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(:IPCCode) }
RETURN count(DISTINCT p) AS cnt_no_ipc

MATCH (p:Patent)-[:HAS_STATUS]->(:LegalStatus {name:'授权'})
WHERE NOT EXISTS { MATCH (p)-[:OWNED_BY]->(:Organization) }
RETURN count(DISTINCT p) AS authorized_without_owner

MATCH (o:Organization)
WHERE EXISTS { MATCH (:Patent)-[:LICENSED_TO]->(o) }
  AND NOT EXISTS { MATCH (:Patent)-[:LICENSED_FROM]->(o) }
RETURN o.name AS org_name
ORDER BY org_name
LIMIT 30

MATCH (p:Patent)
WHERE EXISTS { MATCH (p)-[:LICENSED_TO]->(:Organization) }
  AND EXISTS { MATCH (p)-[:PLEDGED_TO]->(:Organization) }
RETURN p.application_no AS application_no, p.title AS title
ORDER BY p.application_no
LIMIT 20

MATCH (p:Patent)
WHERE EXISTS { MATCH (p)-[:TRANSFERRED_TO]->(:Organization) }
  AND EXISTS { MATCH (p)-[:LITIGATED_WITH]->(:Organization) }
RETURN p.application_no AS application_no, p.title AS title
LIMIT 20

MATCH (p:Patent)
WHERE EXISTS { MATCH (p)-[:PLEDGED_TO]->(:Organization) }
  AND EXISTS { MATCH (p)-[:LITIGATED_WITH]->(:Organization) }
RETURN p.application_no AS application_no, p.title AS title
ORDER BY p.application_no
LIMIT 20

MATCH (p:Patent)
WHERE EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(i1:IPCCode) WHERE i1.code STARTS WITH 'H01M' }
  AND EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(i2:IPCCode) WHERE i2.code STARTS WITH 'F17C' }
RETURN p.application_no AS application_no, p.title AS title
ORDER BY p.application_no
LIMIT 20
